function toTraditionalText(text) {
  let out = String(text);
  for (const [from, to] of zhPhraseMap) {
    out = out.split(from).join(to);
  }
  return Array.from(out).map((ch) => zhCharMap[ch] || ch).join('');
}

export default {
  name: 'FragmentsTab',
  data() {
    return {
      writings,
      activeCategory: 'ideas',
      openIds: []
    };
  },
  computed: {
    copy() {
      return {
        eyebrow: 'Loose fragments',
        heading: 'Fragments',
        intro: 'Loose fragments of thought and life. Some are messy, loosely ordered, and not fully organized; closer to passing reflections than finished essays.',
        read: 'Read',
        close: 'Close',
        toggleLabel: this.activeCategory === 'ideas' ? 'Show life fragments' : 'Show idea fragments'
      };
