    filteredFragments() {
      return this.writings.filter((note) => (note.category || 'ideas') === this.activeCategory);
    }
  },
  methods: {
    toggleCategory() {
      this.activeCategory = this.activeCategory === 'ideas' ? 'life' : 'ideas';
      this.openIds = [];
    },
    isOpen(id) {
      return this.openIds.includes(id);
    },
    toggleNote(id) {
      if (this.isOpen(id)) {
        this.openIds = this.openIds.filter((openId) => openId !== id);
      } else {
        this.openIds = [...this.openIds, id];
      }
      this.$nextTick(() => window.dispatchEvent(new Event('scroll')));
    },
    archivedChineseVersion(note) {
      return toTraditionalText(note.bodyZh || '');
    },
    titleOf(note) {
      return note.titleEn;
    },
    teaserOf(note) {
      return note.teaserEn;
    },
    bodyParagraphs(note) {
      return String(note.bodyEn || '')
        .split(/\n\s*\n/)
        .map((paragraph) => paragraph.trim())
        .filter(Boolean);
    }
  }
};
